/**
 * SMS notification adapter — delivers notifications via SMS.
 *
 * Features:
 * - Phone number validation (E.164 format)
 * - Message formatting based on notification type
 * - Pluggable transport for testability (inject real provider or mock)
 *
 * Implements: NotificationAdapter
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationPayload, NotificationResult } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/**
 * Represents an SMS message ready for transport.
 */
export interface SmsMessage {
  to: string;
  from: string;
  body: string;
}

/**
 * Transport interface — abstracts the actual SMS sending mechanism.
 * Implement this with Twilio, AWS SNS, or a test double.
 */
export interface SmsTransport {
  sendSms(message: SmsMessage): Promise<{ messageId: string }>;
}

export interface SmsConfig {
  /** Sender phone number or short code (E.164 format) */
  from: string;
  /** SMS transport implementation */
  transport: SmsTransport;
}

/**
 * Validate E.164 phone number format: + followed by 1-15 digits.
 */
const PHONE_REGEX = /^\+[1-9]\d{1,14}$/;

function isValidPhoneNumber(phone: string): boolean {
  return PHONE_REGEX.test(phone);
}

/**
 * Format a notification payload into a concise SMS body.
 * SMS messages are limited in length, so we keep them short.
 */
function formatSmsBody(payload: NotificationPayload): string {
  return `${payload.subject}\n${payload.body}`;
}

export class SmsAdapter implements NotificationAdapter {
  readonly channel = 'sms' as const;
  private logger = new Logger('SmsAdapter');

  constructor(private config: SmsConfig) {}

  /**
   * Resolve and validate the recipient phone number.
   * Returns the validated phone number or throws if invalid.
   */
  private resolveRecipient(recipient: string): string {
    const phone = recipient.trim();
    if (!isValidPhoneNumber(phone)) {
      throw new Error(`Invalid SMS recipient phone number: ${recipient}`);
    }
    return phone;
  }

  /**
   * Format a notification payload into an SMS message.
   */
  formatMessage(payload: NotificationPayload): SmsMessage {
    const to = this.resolveRecipient(payload.recipient);
    const body = formatSmsBody(payload);

    return {
      to,
      from: this.config.from,
      body,
    };
  }

  /**
   * Send an SMS notification.
   * Validates recipient, formats message, and delivers via transport.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    try {
      const message = this.formatMessage(payload);

      this.logger.info(`Sending SMS to ${message.to}: "${payload.subject}"`);

      const result = await this.config.transport.sendSms(message);

      this.logger.info(`SMS sent successfully: ${result.messageId}`);

      return {
        success: true,
        notificationId: payload.id,
        channel: this.channel,
        deliveredAt: new Date(),
      };
    } catch (error) {
      const errorMessage = error instanceof Error ? error.message : String(error);
      this.logger.error(`Failed to send SMS to ${payload.recipient}: ${errorMessage}`);

      return {
        success: false,
        notificationId: payload.id,
        channel: this.channel,
        deliveredAt: new Date(),
        error: errorMessage,
      };
    }
  }
}

