import type { NotificationPayload } from '../../src/models/notification.js';

function createMockTransport() {
  return {
    sendSms: vi.fn<(message: SmsMessage) => Promise<{ messageId: string }>>().mockResolvedValue({
      messageId: 'sms-msg-001',
    }),
