}

function createPayload(overrides?: Partial<NotificationPayload>): NotificationPayload {
  return {
    id: 'notif-0001',
    type: 'order-confirmation',
    channel: 'sms',
    recipient: '+14155551234',
    subject: 'Order Confirmation: order-1',
    body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
    priority: 'normal',
    createdAt: new Date('2026-03-30T12:00:00Z'),
    ...overrides,
  };
}

describe('SmsAdapter', () => {
  let transport: ReturnType<typeof createMockTransport>;
  let config: SmsConfig;
  let adapter: SmsAdapter;

  beforeEach(() => {
    transport = createMockTransport();
    config = { from: '+15005550006', transport };
    adapter = new SmsAdapter(config);
  });

  describe('channel', () => {
    it('should report sms as its channel', () => {
      expect(adapter.channel).toBe('sms');
    });
  });

  describe('formatMessage', () => {
    it('should format notification payload as SMS message', () => {
      const payload = createPayload();
      const message = adapter.formatMessage(payload);

      expect(message.to).toBe('+14155551234');
      expect(message.from).toBe('+15005550006');
      expect(message.body).toContain('Order Confirmation: order-1');
      expect(message.body).toContain('Widget x2');
    });

    it('should reject invalid phone numbers', () => {
      const payload = createPayload({ recipient: 'not-a-phone' });
      expect(() => adapter.formatMessage(payload)).toThrow('Invalid SMS recipient phone number');
    });

    it('should reject empty recipients', () => {
      const payload = createPayload({ recipient: '' });
      expect(() => adapter.formatMessage(payload)).toThrow('Invalid SMS recipient phone number');
    });

    it('should reject phone numbers without + prefix', () => {
      const payload = createPayload({ recipient: '14155551234' });
      expect(() => adapter.formatMessage(payload)).toThrow('Invalid SMS recipient phone number');
    });

    it('should reject phone numbers starting with +0', () => {
      const payload = createPayload({ recipient: '+04155551234' });
      expect(() => adapter.formatMessage(payload)).toThrow('Invalid SMS recipient phone number');
    });

    it('should accept valid E.164 phone numbers', () => {
      const payload = createPayload({ recipient: '+447911123456' });
      const message = adapter.formatMessage(payload);
      expect(message.to).toBe('+447911123456');
    });

    it('should trim whitespace from phone numbers', () => {
      const payload = createPayload({ recipient: ' +14155551234 ' });
      const message = adapter.formatMessage(payload);
      expect(message.to).toBe('+14155551234');
    });
  });

  describe('send', () => {
    it('should send SMS via transport and return success', async () => {
      const payload = createPayload();
      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
      expect(result.notificationId).toBe('notif-0001');
      expect(result.channel).toBe('sms');
      expect(result.deliveredAt).toBeInstanceOf(Date);
      expect(result.error).toBeUndefined();

      expect(transport.sendSms).toHaveBeenCalledOnce();
      const [message] = transport.sendSms.mock.calls[0]!;
      expect(message.to).toBe('+14155551234');
      expect(message.from).toBe('+15005550006');
      expect(message.body).toContain('Order Confirmation');
    });

    it('should return failure when transport throws', async () => {
      transport.sendSms.mockRejectedValue(new Error('SMS service unavailable'));

      const payload = createPayload();
      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toBe('SMS service unavailable');
      expect(result.notificationId).toBe('notif-0001');
      expect(result.channel).toBe('sms');
    });

    it('should return failure for invalid recipient', async () => {
      const payload = createPayload({ recipient: 'bad-number' });
      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid SMS recipient phone number');
    });

    it('should handle non-Error thrown values', async () => {
      transport.sendSms.mockRejectedValue('network failure');

      const payload = createPayload();
      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toBe('network failure');
    });
  });
});

